<template>
  <div id="app" style="" v-bind:style="{backgroundImage:'url(' + bg + ')',
        backgroundRepeat:'no-repeat',
        backgroundSize:'100% 100%'}">
    <transition name="el-fade-in-linear">
      <el-row style="height: 100%" type="flex" class="row-bg">
        <el-col :span="6">
          <div class="grid-content bg-purple-light login-panel">
            <el-form ref="loginForm" :model="loginForm" style="padding-top: 15%;padding-left: 20%;padding-right: 20%">
              <el-form-item label="" style="">
                <el-input v-model="loginForm.username" style="width: 100%" placeholder="请输入用户名"></el-input>
              </el-form-item>
              <el-form-item label="">
                <el-input type="password" v-model="loginForm.password" style="" placeholder="请输入用户密码"></el-input>
              </el-form-item>
              <el-form-item label="">
                <el-input v-model="loginForm.googleCode" style="" placeholder="请输入谷歌秘钥"></el-input>
              </el-form-item>
              <el-form-item>
                <el-button type="primary" @click="login" style="width: 36%;height: 32px;line-height: 32px;padding: 0">登录</el-button>
              </el-form-item>
            </el-form>
          </div>
        </el-col>
      </el-row>
    </transition>
  </div>
</template>

<script>
import {login} from "@/api/cpinfo";

export default {
  // eslint-disable-next-line vue/multi-word-component-names
  name: "Login",
  setup(){

  },
  data() {
    return {
      loginForm: {
        username: '',
        password: '',
        googleCode: '',
      },
      bg: require('@/assets/sea_sky.jpeg')

    }
  },
  methods: {
    login() {
      const that = this;

      login(that.loginForm).then((resp) => {
        const msg = resp.data.msg
        const data = resp.data.data
        that.$message(msg)

        if (resp.data.code === 0) {
          localStorage.setItem('CpInfo_Authorization',data)
          that.$router.push('/index')
        }
      })
    }
  }
}
</script>

<style scoped>
 /deep/ .row-bg {
   height: 100%;
  padding: 10px 0;
}



</style>
