<template>
  <!--        <el-row :span="24" style=";height: 2.0rem">-->
  <!--            <div style="float: right;width: 100%;background-color: rgb(245,245,245);margin-bottom: 1rem">-->
  <!--                <marquee style="width: 100%;height: 2.0rem;float: right;line-height: 2.0rem" direction="left"-->
  <!--                         behavior="scroll" scrollamount="3" onmouseover="this.stop();" onmouseout="this.start();"-->
  <!--                         scrolldelay="0" loop="-1" width="211" height="125">-->
  <!--                    <span style="font-family: Arial">内充下发请联系：@kimkumma   @giao265</span>-->
  <!--                </marquee>-->
  <!--            </div>-->
  <!--        </el-row>-->
  <div id="app">
    <el-row :gutter="0">

      <el-col :xl="6" :lg="7" :md="8" :sm="24" :xs="24" class="home-text-remain">
        <label class="home-text-remain-text">可提现：</label>
        <label class="home-text-remain-text">{{ currencySymbol }}</label>
        <label v-bind:style="remainAmount" ref="actualRemain" class="home-text-remain-amount"
               style="color: green">{{ cpinfo.actualRemain }}</label>
      </el-col>
      <el-col :xl="6" :lg="7" :md="8" :sm="24" :xs="24" class="home-text-remain">
        <label class="home-text-remain-text">待结算：</label>
        <label class="home-text-remain-text">{{ currencySymbol }}</label>
        <label v-bind:style="remainAmount" ref="settleRemain"
               class="home-text-remain-amount">{{ cpinfo.settleRemain }}</label>
      </el-col>
      <el-col :xl="6" :lg="7" :md="8" :sm="24" :xs="24" class="home-text-remain">
        <label class="home-text-remain-text">总额度：</label>
        <label class="home-text-remain-text">{{ currencySymbol }}</label>
        <label id="remain" ref="remain" v-bind:style="remainAmount"
               class="home-text-remain-amount">{{ cpinfo.remain }}</label>
      </el-col>

    </el-row>
    <el-row style="margin-top: 30px;margin-bottom: 10px;position: absolute;right: 20px">
      <el-select style="" v-model="searchForm.country" placeholder="选择国家" @change="getCpHomeStatictics()">
        <el-option value="">默认 UTC+8</el-option>
        <el-option :label="cpinfo.country.label" :value="cpinfo.country.value"></el-option>
      </el-select>
    </el-row>
    <el-row style="margin-top: 80px" :gutter="40">
      <el-col :xl="8" :lg="8" :md="8" :sm="12" :xs="24">
        <div class="col">
          <el-card class="box-card">
            <template #header>
              <h1 style="margin-bottom: 10px">今日</h1>
            </template>
            <div class="card-item"><span>代收</span><span>{{ showData.todayPayAmount }}</span>
            </div>
            <div class="card-item"><span>代收手续费</span><span>{{ showData.todayPayFee }}</span>
            </div>
            <div class="card-item"><span>代收订单数</span><span>{{ showData.todayPayNum }}</span></div>
            <div class="card-item"><span>代付</span><span>{{ showData.todayWithdrawAmount }}</span>
            </div>
            <div class="card-item"><span>代付手续费</span><span>{{ showData.todayWithdrawFee }}</span>
            </div>
            <div class="card-item"><span>代付订单数</span><span>{{ showData.todayWithdrawNum }}</span></div>
          </el-card>
        </div>
      </el-col>
      <el-col :xl="8" :lg="8" :md="8" :sm="12" :xs="24">
        <el-card class="box-card">
          <template #header>
            <h1 style="margin-bottom: 10px">昨日</h1>
          </template>
          <div class="card-item"><span>代收</span><span>{{ showData.yesterdayPayAmount }}</span>
          </div>
          <div class="card-item"><span>代收手续费</span><span>{{ showData.yesterdayPayFee }}</span>
          </div>
          <div class="card-item"><span>代收订单数</span><span>{{ showData.yesterdayPayNum }}</span></div>
          <div class="card-item"><span>代付</span><span>{{ showData.yesterdayWithdrawAmount }}</span>
          </div>
          <div class="card-item"><span>代付手续费</span><span>{{ showData.yesterdayWithdrawFee }}</span>
          </div>
          <div class="card-item"><span>代付订单数</span><span>{{ showData.yesterdayWithdrawNum }}</span></div>
        </el-card>
      </el-col>
      <el-col :xl="8" :lg="8" :md="8" :sm="24" :xs="24">
        <el-card class="box-card">
          <template #header>
            <h1 style="margin-bottom: 10px">全部</h1>
          </template>
          <div class="card-item"><span>代收</span><span>{{ showData.totalPayAmount }}</span>
          </div>
          <div class="card-item"><span>代收手续费</span><span>{{ showData.totalPayFee }}</span>
          </div>
          <div class="card-item"><span>代收订单数</span><span>{{ showData.totalPayNum }}</span></div>
          <div class="card-item"><span>代付</span><span>{{ showData.totalWithdrawAmount }}</span>
          </div>
          <div class="card-item"><span>代付手续费</span><span>{{ showData.totalWithdrawFee }}</span>
          </div>
          <div class="card-item"><span>代付订单数</span><span>{{ showData.totalWithdrawNum }}</span></div>
        </el-card>
      </el-col>
    </el-row>
    <el-row :span="24" :gutter="40" style="">
      <div style="width: 100%;height: 20rem;margin-top: 1.5rem">
        <el-col :xs="24">
          <el-card class="box-card">
            <template #header>
              <div class="card-header">
                <span>商户信息</span>
                <el-button style="float: right; padding: 3px 0" type="text"
                           @click="openCpInfoSettingDrawer()">商户配置
                </el-button>
              </div>
            </template>

            <div class="text item" style="text-align: left">
              <span>{{ cpinfoSetting.appid.label }}</span><span>{{ cpinfoSetting.appid.value }}</span>
            </div>
            <div class="text item" style="text-align: left">
              <span>{{ cpinfoSetting.key.label }}</span>
              <span v-if="showKey">{{ cpinfoSetting.key.value }}</span>
              <span v-else>*******************************</span>
              <el-link href="#" class="home-cpinfo-show" @click="showCheckPasswordDialog = true">显示</el-link>
            </div>
            <div class="text item" style="text-align: left">
              <span>{{ cpinfoSetting.googleSecret.label }}</span>
              <span>{{ cpinfoSetting.googleSecret.value }}</span>
            </div>
          </el-card>
        </el-col>
      </div>
      <el-dialog
          title="验证登录密码"
          v-model="showCheckPasswordDialog"
          width="20%"
          center>
        <el-input v-model="checkPasswordDialog.password" placeholder="请输入密码"></el-input>
        <span class="dialog-footer">
    <el-button @click="showCheckPasswordDialog = false">取 消</el-button>
    <el-button type="primary" @click="checkPassword(checkPasswordDialog.password)">确 定</el-button>
  </span>
      </el-dialog>
      <el-drawer
          title="商户配置"
          v-model="showCpInfoSettingDrawer"
          direction="rtl"
          :before-close="handleClose"
          size="50%"
      >
        <div style="width: 100%;height: 100%;padding: 1rem">
          <el-form label-width="6rem">
            <el-form-item label="商户Id">
              <el-input readonly disabled v-model="cpinfoSetting.appid.value"
                        style="width: 12rem"></el-input>
            </el-form-item>
            <el-form-item label="用户名">
              <el-input readonly disabled v-model="cpinfoSetting.userName.value"
                        style="width: 12rem"></el-input>
            </el-form-item>
            <el-form-item label="代收费率">
              <el-input readonly disabled v-model="cpinfoSetting.withdrawFee.value"
                        style="width: 12rem"></el-input>
            </el-form-item>
            <el-form-item label="代付费率">
              <el-input readonly disabled v-model="cpinfoSetting.payFee.value"
                        style="width: 12rem"></el-input>
            </el-form-item>
            <el-divider></el-divider>
          </el-form>
          <el-form :rules="rules" ref="cpInfoSettingForm" :model="cpInfoSettingForm" label-width="6rem">
            <el-form-item label="原始密码" prop="passwordOri">
              <el-input show-password="true" v-model="cpInfoSettingForm.passwordOri"
                        style="width: 12rem"></el-input>
            </el-form-item>
            <el-form-item label="新密码" prop="passwordNew">
              <el-input show-password="true" v-model="cpInfoSettingForm.passwordNew"
                        style="width: 12rem"></el-input>
            </el-form-item>
            <el-form-item label="确认密码" prop="passwordNewAgain">
              <el-input show-password="true" v-model="cpInfoSettingForm.passwordNewAgain"
                        style="width: 12rem"></el-input>
            </el-form-item>
            <el-form-item>
              <el-button type="primary" @click="changePassword">修改密码</el-button>
              <el-button type="primary" @click="resetCpInfoSettingForm">重置</el-button>
            </el-form-item>
          </el-form>
          <el-form label-width="6rem">
            <el-divider></el-divider>
            <el-form-item label="google秘钥">
              <el-input readonly v-model="cpInfoSettingGoogleSecretForm.googleSecret"></el-input>
            </el-form-item>
            <el-form-item>
              <el-button type="primary" @click="createGoogleSecret()">生成新的google秘钥并套用</el-button>
            </el-form-item>
            <el-form-item>
              <el-button @click="closeCpInfoSettingDrawer()">取消</el-button>
            </el-form-item>
          </el-form>
        </div>
      </el-drawer>
    </el-row>
  </div>
</template>

<script>
import {
  changePassword,
  checkPassword,
  createGoogleSecret,
  getCpHomeStatictics,
  getCpInfoRemain,
  getSessionCpInfo
} from "@/api/cpinfo";
import {formatAmount} from "@/statics/custom";

export default {
  name: `Home`,
  data() {
    return {
      fullscreenLoading: false,
      searchForm: {
        country: ''
      },
      currencySymbol: '',
      cpinfo: {
        actualRemain: '',
        settleRemain: '',
        remain: '',
        country: {
          label: '',
          value: ''
        }
      },
      showData: {
        todayPayAmount: 0,
        todayPayFee: 0,
        todayPayNum: 0,
        todayWithdrawAmount: 0,
        todayWithdrawFee: 0,
        todayWithdrawNum: 0,
        totalPayAmount: 0,
        totalPayFee: 0,
        totalPayNum: 0,
        totalWithdrawAmount: 0,
        totalWithdrawFee: 0,
        totalWithdrawNum: 0,
        yesterdayPayAmount: 0,
        yesterdayPayFee: 0,
        yesterdayPayNum: 0,
        yesterdayWithdrawAmount: 0,
        yesterdayWithdrawFee: 0,
        yesterdayWithdrawNum: 0,
      },
      cpinfoSetting: {
        appid: {
          label: '商户Id:',
          value: '',
        },
        userName: {
          value: ''
        },
        key: {
          label: '秘钥Key:',
          value: '',
        },
        googleSecret: {
          label: '谷歌秘钥:',
          value: '',
        },
        payFee: {
          value: ''
        },
        withdrawFee: {
          value: ''
        }
      },
      showKey: false,
      showGoogleSecret: false,
      clientHeight: 0,
      remainAmount: {
        fontSize: '1.5rem'
      },
      showCheckPasswordDialog: false,
      checkPasswordDialog: {
        password: ''
      },
      showCpInfoSettingDrawer: false,
      cpInfoSettingForm: {
        appId: '',
        userName: '',
        passwordOri: '',
        passwordNew: '',
        passwordNewAgain: '',
        key: ''
      },
      cpInfoSettingGoogleSecretForm: {
        googleSecret: ''
      },
      rules: {
        passwordOri: [
          {required: true, message: '请输入旧密码', trigger: 'blur'}
        ],
        passwordNew: [
          {required: true, message: '请输入新密码', trigger: 'blur'}
        ],
        passwordNewAgain: [
          {required: true, message: '请再输入一次新密码', trigger: 'blur'}
        ]
      }

    }
  },
  created() {
    this.getCpHomeStatictics()
    this.getCpInfoRemain()
    this.getCpInfo()
  },
  methods: {
    getCpHomeStatictics: function () {
      var that = this
      getCpHomeStatictics(this.searchForm).then(function (response) {
        if (response.data.code === 0) {
          var data = response.data.data
          that.showData.todayPayAmount = formatAmount(data.todayPayAmount)
          that.showData.todayPayFee = formatAmount(data.todayPayFee)
          that.showData.todayPayNum = data.todayPayNum
          that.showData.yesterdayPayAmount = formatAmount(data.yesterdayPayAmount)
          that.showData.yesterdayPayFee = formatAmount(data.yesterdayPayFee)
          that.showData.yesterdayPayNum = data.yesterdayPayNum
          that.showData.todayWithdrawAmount = formatAmount(data.todayWithdrawAmount)
          that.showData.todayWithdrawFee = formatAmount(data.todayWithdrawFee)
          that.showData.todayWithdrawNum = data.todayWithdrawNum
          that.showData.yesterdayWithdrawAmount = formatAmount(data.yesterdayWithdrawAmount)
          that.showData.yesterdayWithdrawFee = formatAmount(data.yesterdayWithdrawFee)
          that.showData.yesterdayWithdrawNum = data.yesterdayWithdrawNum
          that.showData.totalPayAmount = formatAmount(data.totalPayAmount)
          that.showData.totalPayFee = formatAmount(data.totalPayFee)
          that.showData.totalPayNum = data.totalPayNum
          that.showData.totalWithdrawAmount = formatAmount(data.totalWithdrawAmount)
          that.showData.totalWithdrawFee = formatAmount(data.totalWithdrawFee)
          that.showData.totalWithdrawNum = data.totalWithdrawNum

          that.fullscreenLoading = false
        }
      })

    },
    getCpInfoRemain() {
      var that = this
      getCpInfoRemain().then(function (response) {
        if (response.data.code === 0) {
          var data = response.data.data
          that.cpinfo.remain = formatAmount(data.remain)
          that.cpinfo.actualRemain = formatAmount(data.actualRemain)
          that.cpinfo.settleRemain = formatAmount(data.settleRemain)

          if (Number(that.cpinfo.remain) > 9999) {
            that.remainAmount.fontSize = '1.4rem'
          } else if (!(Number(that.cpinfo.remain) <= 9999)) {
            that.remainAmount.fontSize = '1.2rem'
          }
          var country = data.country

          if (country === 'IND') {
            that.currencySymbol = '₹'
            that.cpinfo.country = {
              label: '印度 UTC+5',
              value: 'IND'
            }
          } else if (country === 'MEX') {
            that.currencySymbol = 'MX$'
            that.cpinfo.country = {
              label: '墨西哥 UTC-5',
              value: 'MEX'
            }
          } else if (country === 'BRA') {
            that.currencySymbol = 'R$'
            that.cpinfo.country = {
              label: '巴西 UTC-3',
              value: 'BRA'
            }
          }
          that.fullscreenLoading = false
        }
      })
    },
    getCpInfo() {
      getSessionCpInfo().then((res) => {
        console.log(res)
        const code = res.data.code
        const msg = res.data.msg
        const data = res.data.data
        if (code === 0) {
          this.cpinfoSetting.appid.value = data.appId
          this.cpinfoSetting.key.value = data.key
          this.cpinfoSetting.googleSecret.value = data.googleSecret
          this.cpinfoSetting.userName.value = data.userName
          this.cpinfoSetting.payFee.value = data.payFeeRate + '+' + data.payFeeFix
          this.cpinfoSetting.withdrawFee.value = data.withdrawFeeRate + '+' + data.withdrawFeeFix
        }
      })
    },
    checkPassword(data) {
      var that = this
      checkPassword({
        password: data
      }).then(function (response) {
        if (response.data.code === 0 && response.data.msg === 'true') {
          that.showKey = true
          that.showCheckPasswordDialog = false
        }
      })
    },
    openCpInfoSettingDrawer() {
      this.showCpInfoSettingDrawer = true
      this.cpInfoSettingForm.appId = this.cpinfoSetting.appid.value
      this.cpInfoSettingForm.userName = this.cpinfoSetting.userName.value
      this.cpInfoSettingForm.key = this.cpinfoSetting.key.value
      this.cpInfoSettingGoogleSecretForm.googleSecret = this.cpinfoSetting.googleSecret.value
    },
    closeCpInfoSettingDrawer() {
      this.showCpInfoSettingDrawer = false
      this.$refs.cpInfoSettingForm.resetFields()
    },
    handleClose() {
      this.showCpInfoSettingDrawer = false

    },
    onSubmit() {

    },
    createGoogleSecret() {
      var that = this
      createGoogleSecret().then(function (response) {
        if (response.data.code === 0) {
          var data = response.data.data
          that.cpInfoSettingGoogleSecretForm.googleSecret = data.googleSecret
        }
      })
    },
    resetCpInfoSettingForm() {
      this.$refs.cpInfoSettingForm.resetFields()
      this.cpInfoSettingForm.passwordOri = ''
      this.cpInfoSettingForm.passwordNew = ''
      this.cpInfoSettingForm.passwordNewAgain = ''
    },
    changePassword() {
      const that = this
      changePassword(this.cpInfoSettingForm).then(function (response) {
        const msg = response.data.msg
        if (response.data.code === 0) {
          that.resetCpInfoSettingForm()
          that.$message(msg)
          that.$router.push('/')
        } else {
          that.$message(msg);
        }
      })
    },
  }
}
</script>
<style>
html, body, #app, .el-container {
  border-style: none;
  overflow-x: hidden;
  /*设置内部填充为0，几个布局元素之间没有间距*/
  padding: 0px;
  /*外部间距也是如此设置*/
  margin: 0px;
  /*统一设置高度为100%*/
  height: 100%;
}

.text {
  font-size: 14px;
}

.item {
  margin-bottom: 18px;
  height: 1rem;
}

.clearfix:before,
.clearfix:after {
  position: relative;
  content: "";
}

.clearfix:after {
  clear: both
}


.col {
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.text {
  font-size: 14px;
}

.item {
  margin-bottom: 18px;
}

.box-card {
  width: 100%;
}
</style>

