<template>
  <div id="app" v-cloak v-loading.fullscreen.lock="fullscreenLoading">
    <el-form :model="searchForm" ref="searchForm" label-width="90px">
      <el-row>
        <el-col :xl="3" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="系统订单号" prop="id">
            <el-input v-model="searchForm.id" placeholder=""></el-input>
          </el-form-item>
        </el-col>
        <el-col :xl="3" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="商户订单号" prop="orderId">
            <el-input v-model="searchForm.orderId" placeholder=""></el-input>
          </el-form-item>
        </el-col>
        <el-col :xl="3" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="订单状态" prop="status">
            <el-select v-model="searchForm.status" placeholder="请选择" value="">
              <el-option label="请选择" value=""></el-option>
              <el-option label="成功" value="2"></el-option>
              <el-option label="处理中" value="1"></el-option>
              <el-option label="失败" value="-2"></el-option>
            </el-select>
          </el-form-item>
        </el-col>
        <el-col :xl="3" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="同步状态" prop="syncCnt">
            <el-select v-model="searchForm.syncCnt" placeholder="请选择">
              <el-option label="请选择" value=""></el-option>
              <el-option label="同步成功" value="1"></el-option>
              <el-option label="未回调" value="0"></el-option>
              <el-option label="失败重试" value="-1"></el-option>
            </el-select>
          </el-form-item>
        </el-col>
      </el-row>
      <el-row>
        <el-col :xl="4" :lg="8" :md="8" :sm="12" :xs="24" class="form-search">
          <el-form-item label="起始时间">
            <el-col :span="11">
              <el-date-picker
                  v-model="createDate"
                  type="datetimerange"
                  :default-time="defaultTime"
                  value-format="YYYY-MM-DD HH:mm:ss"
                  placeholder="选择起始日期"
                  :picker-options="pickerOptionsStart">
              </el-date-picker>
            </el-col>
          </el-form-item>
        </el-col>

      </el-row>
      <el-row>
        <el-col :xl="3" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="银行账号" prop="bankCardNo">
            <el-input v-model="searchForm.bankCardNo" placeholder=""></el-input>
          </el-form-item>
        </el-col>
        <el-col v-if="cpinfo.country === 'BRA'" :xl="3" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="CPF" prop="cpf">
            <el-input v-model="searchForm.cpf" placeholder=""></el-input>
          </el-form-item>
        </el-col>
        <el-col v-if="cpinfo.country === 'BRA'" :xl="3" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="PIX账号" prop="pix_key">
            <el-input v-model="searchForm.pix_key" placeholder=""></el-input>
          </el-form-item>
        </el-col>
      </el-row>
      <el-row>
        <el-button type="primary" @click="search">查询</el-button>
        <el-button @click="resetForm('searchForm')">重置</el-button>
        <el-button @click="exportWithdrawLog()">导出</el-button>
      </el-row>
    </el-form>

    <div id="grid" style="width: 100%;margin-top: 20px">
      <el-table
          :data="tableData"
          style="width: 100%"
          size="small"
      >
        <el-table-column type="expand">
          <template #default="props">
            <el-form label-position="left" inline class="demo-table-expand">
              <el-form-item label="回调地址">
                <span>{{ props.row.notifyUrl }}</span>
              </el-form-item>
              <el-form-item label="ip">
                <span>{{ props.row.ip }}</span>
              </el-form-item>
              <el-form-item label="姓名">
                <span>{{ props.row.bankAccountName }}</span>
              </el-form-item>
              <el-form-item label="邮箱">
                <span>{{ props.row.email }}</span>
              </el-form-item>
              <el-form-item label="手机号">
                <span>{{ props.row.mobile }}</span>
              </el-form-item>
            </el-form>
          </template>
        </el-table-column>
        <el-table-column
            prop="id"
            label="订单号"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="orderId"
            label="商户订单号"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="appId"
            label="商户Id"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="amount"
            label="金额"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="platformFee"
            label="商户手续费"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="bankCardNo"
            label="银行账号"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="documentId"
            label="CPF"
            v-if="cpinfo.country === 'BRA'"
            align="center"

        >
        </el-table-column>
        <el-table-column
            prop="pixKey"
            label="Pix账号"
            v-if="cpinfo.country === 'BRA'"
            align="center"

        >
        </el-table-column>
        <el-table-column
            prop="type"
            label="到账类型"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="bankCode"
            label="银行编号"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="branchCode"
            label="分行编号"
            align="center"
        >
        </el-table-column>
        <el-table-column
            label="订单状态"
            align="center"

        >
          <template #default="scope">
            <span v-if="scope.row.status === 1 || scope.row.status === 0 || scope.row.status === -1 " class="settlement-status settlement-status-initial">处理中</span>
            <span v-if="scope.row.status  === 2" class="settlement-status settlement-status-success">成功</span>
            <span v-if="scope.row.status  === -2" class="settlement-status settlement-status-reject">失败</span>
          </template>

        </el-table-column>
        <el-table-column
            label="回调状态"
            width="90px"
            align="center"

        >
          <template #default="scope">
            <span v-if="scope.row.syncCnt  === 1" class="settlement-status settlement-status-success">同步成功</span>
            <span v-if="scope.row.syncCnt  === 0" class="settlement-status settlement-status-initial">待同步</span>
            <span v-if="scope.row.syncCnt  < 0" class="settlement-status settlement-status-reject">同步失败</span>
          </template>
        </el-table-column>
        <el-table-column
            prop="createTime"
            label="创建时间"
            align="center"
        >
        </el-table-column>
        <el-table-column label="操作" width="300">
          <template #default="scope">
            <el-button v-if="false" :disabled="(scope.row.status !== '成功' && scope.row.status !== '失败')"
                       type="success"
                       round
                       @click="openSendNotifyMsgDrawer(scope.row)"
            >补发通知
            </el-button>
          </template>
        </el-table-column>
      </el-table>
    </div>
    <div style="text-align: center;margin-top:5px;">
      <el-pagination
          background
          layout="total, prev, pager, next"
          :total="total" :current-page="searchForm.page" @current-change="pageChange">
      </el-pagination>
    </div>
  </div>
</template>

<script>
import {queryWithdrawLogPageList} from "@/api/withdrawLog";
import {dateFormate, formatAmount, formatWithdrawType} from "@/statics/custom";

export default {
  // eslint-disable-next-line vue/multi-word-component-names
  name: "index",
  data() {
    return {
      fullscreenLoading: false,
      sendNotifyDrawerVisable: false,
      direction: 'rtl',
      createDate: [],
      withdrawDate: [],
      countryOptions: [],
      searchForm: {
        id: '',
        appId: '',
        amount: '',
        orderId: '',
        type: '',
        status: '',
        syncCnt: '',
        bankCardNo: '',
        cpf: '',
        pix_key: '',
        startCreateTime: '',
        endCreateTime: '',
        startPayTime: '',
        endPayTime: '',
        page: 1,
        limit: 10,
        rowIndex: 0
      },
      tableData: [],
      total: 0,
      withdrawTypeOptions: [],
      sendNotifyMsgForm: {
        id: '',
        url: '',
        notifyData: '',
        notifyResp: '',
        notifyAnalyze: ''
      },
      formLabelWidth: 120,
      sending: false,
      cpinfo: {
        country: ''
      },
      defaultTime: [
        new Date(2000, 1, 1, 0, 0, 0),
        new Date(2000, 2, 1, 23, 59, 59),
      ],
    }
  },
  created() {
    this.queryAllWithdrawLog()
    this.initCpinfo()
  },
  methods: {
    queryAllWithdrawLog() {
      var that = this
      that.fullscreenLoading = true
      this.searchForm.startCreateTime = this.createDate.length === 0 ? '' : this.createDate[0]
      this.searchForm.endCreateTime = this.createDate.length === 0 ? '' : this.createDate[1]

      queryWithdrawLogPageList(that.searchForm).then(function (response) {
        if (response.data.code === 0) {
          var list = response.data.data.list
          var statictics = response.data.data.statictics

          var tableData = []
          for (var withdrawlog of list) {
            var currency = withdrawlog.currency
            var type = withdrawlog.type
            if (currency === 'BRL' && type === '4') {
              withdrawlog.BankCardNo = withdrawlog.pixKey
            }
            withdrawlog.type = formatWithdrawType(withdrawlog)

            withdrawlog.amount = formatAmount(withdrawlog.amount)
            withdrawlog.platformFee = formatAmount(withdrawlog.platformFee)
            withdrawlog.thirdFee = formatAmount(withdrawlog.thirdFee)

            var status = withdrawlog.status
            withdrawlog.status = status

            withdrawlog.createTime = dateFormate(withdrawlog.createTime)

            tableData.push(withdrawlog)
          }
          that.tableData = tableData
          that.total = statictics.allWithdrawNum
          that.fullscreenLoading = false
        }
      })
    },
    search() {
      this.searchForm.page = 1
      this.queryAllWithdrawLog()
    },
    resetForm(name) {
      this.$refs[name].resetFields()
      this.createDate = []
      this.searchForm.startCreateTime = ''
      this.searchForm.endCreateTime = ''
      this.searchForm.startPayTime = ''
      this.searchForm.endPayTime = ''
    },
    pageChange(cur) {
      this.searchForm.page = cur
      this.queryAllWithdrawLog()
    },
    closeDialog() {
      this.dialog.visible = false
      this.dialog.isInsert = true
    },
    openSendNotifyMsgDrawer(data) {
      this.sendNotifyMsgForm.id = ''
      this.sendNotifyMsgForm.id = data.id
      this.sendNotifyMsgForm.url = ''
      this.sendNotifyMsgForm.url = data.notifyUrl
      this.sendNotifyMsgForm.notifyData = ''
      this.sendNotifyMsgForm.notifyResp = ''
      this.sendNotifyMsgForm.notifyAnalyze = ''
      this.sendNotifyDrawerVisable = true
    },
    handleClose(done) {
      done();
    },
    cancelNotifyMsgDrawer() {
      this.sendNotifyDrawerVisable = false
      this.sendNotifyMsgForm.notifyData = ''
      this.sendNotifyMsgForm.notifyResp = ''
      this.sendNotifyMsgForm.notifyAnalyze = ''
    },
    initCpinfo() {
      var data = JSON.parse(sessionStorage.getItem("cpinfo"))
      this.cpinfo.country = data.country
    },
    exportWithdrawLog() {
      console.log(this.searchForm)
      //编码防止中文字符乱码
      window.location.href = encodeURI("/pay/withdrawlog/exportWithdrawLog?id=" + this.searchForm.id + "&appId=" + this.searchForm.appId + "&amount=" + this.searchForm.amount + "&orderId=" + this.searchForm.orderId + "&type=" + this.searchForm.type + "&status=" + this.searchForm.status + "&syncCnt=" + this.searchForm.syncCnt + "&bankCardNo=" + this.searchForm.bankCardNo + "&cpf=" + this.searchForm.cpf + "&pix_key=" + this.searchForm.pix_key + "&startCreateTime=" + (this.searchForm.startCreateTime === undefined ? "" : this.searchForm.startCreateTime) + "&endCreateTime=" + (this.searchForm.endCreateTime === undefined ? "" : this.searchForm.endCreateTime));
    }
  }
}
</script>

<style scoped>

</style>
