<template>
  <div id="app" v-cloak v-loading.fullscreen.lock="fullscreenLoading">
    <el-form :model="searchForm" ref="searchForm" label-width="90px">
      <el-row>
        <el-col :xl="4" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="订单状态" prop="status">
            <el-select v-model="searchForm.status" placeholder="请选择">
              <el-option label="请选择" value=""></el-option>
              <el-option label="成功" value="1"></el-option>
              <el-option label="待处理" value="0"></el-option>
              <el-option label="失败" value="-1"></el-option>
            </el-select>
          </el-form-item>
        </el-col>
        <el-col :xl="4" :lg="8" :md="8" :sm="12" :xs="24" class="form-search">
          <el-form-item label="起始时间">
            <el-col :span="11">
              <el-date-picker
                  v-model="early"
                  type="datetimerange"
                  :clearable="true"
                  :default-time="['00:00:00', '23:59:59']"
                  value-format="yyyy-MM-dd HH:mm:ss"
                  placeholder="选择起始日期"
                  :picker-options="pickerOptionsStart">
              </el-date-picker>
            </el-col>
          </el-form-item>
        </el-col>
      </el-row>
      <el-row>
        <el-button type="primary" @click="search">查询</el-button>
        <el-button @click="resetForm('searchForm')">重置</el-button>
        <el-button @click="openSettlementLogDialog">申请结算</el-button>
      </el-row>

    </el-form>
    <div id="grid" style="width: 100%;margin-top: 20px">
      <el-table
          :data="tableData"
          style="width: 100%"
          size="small"
      >
        <el-table-column type="expand">
          <template #default="props">
            <el-form label-position="left" inline class="demo-table-expand">

            </el-form>
          </template>
        </el-table-column>
        <el-table-column
            prop="id"
            label="订单号"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="appId"
            label="商户Id"
            align="center">
        </el-table-column>
        <el-table-column
            prop="faitAmount"
            label="结算金额"
            align="center">
        </el-table-column>
        <el-table-column
            prop="account"
            label="账户号"
            align="center"
            min-width="300px"
        >
        </el-table-column>
        <el-table-column
            label="状态"
            align="center">
          <template #default="scope">
            <span v-if="scope.row.status  === 1" class="settlement-status settlement-status-success">已完成</span>
            <span v-if="scope.row.status  === 0" class="settlement-status settlement-status-initial">待处理</span>
            <span v-if="scope.row.status  === -1" class="settlement-status settlement-status-reject">拒绝</span>
          </template>
        </el-table-column>
<!--        <el-table-column-->
<!--            prop="rate"-->
<!--            label="结算汇率"-->
<!--            align="center"-->
<!--        ></el-table-column>-->
<!--        <el-table-column-->
<!--            prop="uAmount"-->
<!--            label="usdt金额"-->
<!--            align="center">-->
<!--        </el-table-column>-->
<!--        <el-table-column-->
<!--            prop="proof"-->
<!--            label="凭证"-->
<!--            align="center">-->
<!--        </el-table-column>-->
        <el-table-column
            prop="createTime"
            label="创建时间"
            align="center">
        </el-table-column>
        <el-table-column
            prop="finishTime"
            label="完成时间"
            align="center">
        </el-table-column>
      </el-table>
    </div>
    <div style="text-align: center;margin-top:5px;">
      <el-pagination
          background
          layout="total, prev, pager, next"
          :total="total" :current-page="searchForm.page" @current-change="pageChange">
      </el-pagination>
    </div>
    <el-dialog width="68%" class="settlementLogDialog" v-model="settlementLogDialogVisiable" title="结算余额">
      <div style="padding: 10px">

        <el-form :model="addForm" ref="addForm" label-width="80px" :rules="addFormRules">
          <div class="settlement-dialog-remain-info">
            <el-col :xl="12" :lg="12" :md="12" :sm="12" :xs="24">
              商户余额：<span style="color: #42b983;margin-right: 20px">{{ cpInfoRemain.remain }}</span>
            </el-col>
            <el-col :xl="12" :lg="12" :md="12" :sm="12" :xs="24">
              可用额度：{{ cpInfoRemain.actualRemain }}
            </el-col>
          </div>
          <el-col style="width: 100%;margin-top: 20px">
            <el-form-item label="结算产品"  prop="product">
              <el-select v-model="addForm.product" placeholder="默认">
                <el-option label="默认" value="1"></el-option>
              </el-select>
            </el-form-item>
          </el-col>
          <el-col style="width: 100%">
            <el-form-item label="银行卡"  prop="card">
              <el-select v-model="addForm.card" placeholder="默认">
                <el-option label="默认" value="1" ></el-option>
              </el-select>
            </el-form-item>
          </el-col>
          <el-col style="width: 100%">
            <el-form-item label="账户属性"  prop="accountType">
              <el-radio v-model="addForm.accountType" label="1">对公</el-radio>
              <el-radio v-model="addForm.accountType" label="2">对私</el-radio>
            </el-form-item>
          </el-col>
          <el-col style="width: 100%">
            <el-form-item label="开户行"  prop="bankName">
              <el-input style="width: 160px" v-model="addForm.bankName" autocomplete="off"></el-input>
            </el-form-item>
          </el-col>
          <el-col style="width: 100%">
            <el-form-item label="开户网点"  prop="bankNetName">
              <el-input style="width: 160px" v-model="addForm.bankNetName" autocomplete="off"></el-input>
            </el-form-item>
          </el-col>
          <el-col style="width: 100%">
            <el-form-item label="账户名"  prop="accountName">
              <el-input style="width: 160px" v-model="addForm.accountName" autocomplete="off"></el-input>
            </el-form-item>
          </el-col>
          <el-col style="width: 100%">
            <el-form-item label="账户号"  prop="account">
              <el-input style="width: 160px" v-model="addForm.account" autocomplete="off"></el-input>
            </el-form-item>
          </el-col>
          <el-col style="width: 100%">
            <el-form-item label="结算金额"  prop="faitAmount">
              <el-input style="width: 160px" v-model="addForm.faitAmount" autocomplete="off"></el-input>
            </el-form-item>
          </el-col>
        </el-form>
      </div>

      <template #footer>
      <span class="dialog-footer">
        <el-button @click="closeSettlementLogDialog">取消</el-button>
        <el-button type="primary" @click="settlement()"
        >结算</el-button
        >
      </span>
      </template>
    </el-dialog>
  </div>
</template>

<script>
import {pageList, settlement} from "@/api/settlement";
import {getCpInfoRemain} from "@/api/cpinfo";
import {formatAmount, toDecimalString} from "@/statics/custom";

export default {
  // eslint-disable-next-line vue/multi-word-component-names
  name: "index",
  data() {
    var checkFaitAmount = (rule, value, callback) => {
      if (!value) {
        return callback(new Error('请输入结算金额'));
      }
      setTimeout(() => {
        console.log(value)
        let amountReg = /^(([1-9]{1}\d*)|(0{1}))(\.\d{1,2})?$/
        if (!amountReg.test(value)) {
          callback(new Error('请输入数字值'));
        } else {
          callback();
        }
      }, 1000);
    };


    return {
      fullscreenLoading: false,
      early: [],
      searchForm: {
        status: '',
        startCreateTime: '',
        endCreateTime: '',
        startFinishTime: '',
        endFinishTime: '',
        page: 0,
        limit: 10
      },
      tableData: [],
      total: 0,
      settlementLogDialogVisiable: false,
      cpInfoRemain: {
        remain: 0,
        frozenRemain: 0,
        actualRemain: 0,
        country: ''
      },
      addForm: {
        product: '1',
        card: '1',
        accountType: '1',
        bankName: '',
        bankNetName: '',
        accountName: '',
        account: '',
        faitAmount: ''
      },
      addFormRules:{
        product: [
          { required: true, message: '请选择产品', trigger: 'blur' },
        ],
        card: [
          { required: true, message: '请选择银行卡', trigger: 'blur' },
        ],
        accountType: [
          { required: true, message: '请选择账号属性', trigger: 'blur' },
        ],
        bankName: [
          { required: true, message: '请输入开户行', trigger: 'blur' },
        ],
        bankNetName: [
          { required: true, message: '请输入开户网点', trigger: 'blur' },
        ],
        accountName: [
          { required: true, message: '请输入账户名', trigger: 'blur' },
        ],
        account: [
          { required: true, message: '请输入账户号', trigger: 'blur' },
        ],
        faitAmount:[
          { validator: checkFaitAmount,required: true,  trigger: 'blur' },
        ]
      },

      formLabelWidth: '140px',
      pickerOptionsStart: {},
      pickerOptionsEnd: {
        disabledDate(time) {
          let startCreateTime = null
          if (this.dateStart) {
            // 让用户可以选择开始结束同一天
            startCreateTime = new Date(this.dateStart).valueOf() - 8.64e7 + 1;
          } else {
            startCreateTime = Date.now() - 8.64e7;
          }
          return time && time.valueOf() < startCreateTime
        }
      },
    }
  },
  created() {
    this.pageList()
  },
  methods: {
    pageList() {
      const that = this
      pageList(this.searchForm).then((resp) => {
        const code = resp.data.code
        const msg = resp.data.msg
        const data = resp.data.data

        if (code === 0) {

          for (const listElement of data.list) {
            listElement.faitAmount = toDecimalString(listElement.faitAmount)
          }

          that.tableData = data.list



          that.total = data.statistics.totalAllNum
        }
      })
    },
    resetForm(formName) {
      this.$refs[formName].resetFields
    },
    search() {
      this.pageList()
    },
    pageChange(cur) {
      this.searchForm.page = cur
      this.pageList()
    },
    openSettlementLogDialog() {
      this.getCpInfo()
      this.settlementLogDialogVisiable = true
    },
    closeSettlementLogDialog() {
      console.log(this.$refs['addForm'])
      this.$refs['addForm'].resetFields()
      this.settlementLogDialogVisiable = false
    },
    getCpInfo() {
      const that = this
      getCpInfoRemain().then(function (response) {
        if (response.data.code === 0) {
          var data = response.data.data
          that.cpInfoRemain.remain = toDecimalString(data.remain)
          that.cpInfoRemain.actualRemain = toDecimalString(data.actualRemain)
        }
      })
    },
    settlement() {
      const that = this
      that.$refs.addForm.validate((valid)=>{
        if (valid){
          settlement(that.addForm).then((resp) => {
            const code = resp.data.code
            if (code === 0) {
              that.closeSettlementLogDialog()
              that.pageList()
            }
          })
        }
      })

    }
  }
}
</script>

