<template>
  <el-container>
    <el-aside :width="asideWidth" ref="el-aside" style="background-color: #545c64">
      <div class="top-info" v-if="!isCollapse">
        <el-row :span="24">
          <el-col :span="24">
            <div class="top-info__image">
              <img src="@/assets/top1.png" style="width: 5rem;border-radius: 3rem" alt="">
            </div>
          </el-col>
        </el-row>
      </div>
      <el-menu
          text-color="white"
          background-color="#545c64"
          active-text-color="#ffd04b"
          class="el-menu-vertical-demo"
          style="border: none"
          :collapse-transition="false" default-active="1" :collapse="isCollapse">
        <el-menu-item index="0" @click="addTabs({ id: 1, permissName: '首页', pValue: 'home' })">
          <home-filled style="width: 25px"></home-filled>
          <span style="font-weight: bold;margin-left: 6px">首页</span>
        </el-menu-item>
        <el-sub-menu class="submenu-hover" v-for="item in menuList" :index="item.permissName"
                     :key="item.id" d>
          <template #title>
            <component :is="item.pType" style="width: 25px"></component>
            <span style="font-weight: bold;margin-left: 6px">{{ item.permissName }}</span>
          </template>
          <el-menu-item-group>
            <el-menu-item v-for="itemson in item.children" :index="itemson.permissName"
                          :key="itemson.id" @click="addTabs(itemson)">
              <component :is="itemson.pType" style="width: 25px"></component>
              <span style="font-weight: bold;margin-left: 6px">{{ itemson.permissName }}</span>
            </el-menu-item>
          </el-menu-item-group>
        </el-sub-menu>
      </el-menu>
    </el-aside>
    <el-container>
      <el-header>
        <div class="page-nav-header">
          <div class="header__left" @click="ShowNavMenu">

            <el-expand v-if="isCollapse" style="width: 30px" @click="asideWidth = '14rem'"></el-expand>
            <el-fold v-else style="width: 30px" @click="asideWidth = '4rem'"></el-fold>
          </div>
          <div class="header__right">
            <el-dropdown>
              <el-icon style="margin-right: 8px; margin-top: 1px"
              >
                <setting
                />
              </el-icon>
              <template #dropdown>

              </template>
            </el-dropdown>
            <span style="color:#f03e41;">{{ cpinfo.username }}</span>
            <el-link style="margin-left: 10px" @click="checkoutLogin">退出登录</el-link>
          </div>
          <!--                        <div style="float: right;width: 100%;background-color: rgb(245,245,245);margin-bottom: 1rem">-->
          <!--                            <marquee style="width: 100%;height: 2.0rem;float: right;line-height: 2.0rem" direction="left"-->
          <!--                                     behavior="scroll" scrollamount="3" onmouseover="this.stop();" onmouseout="this.start();"-->
          <!--                                     scrolldelay="0" loop="-1" width="211" height="125">-->
          <!--                                <span style="font-family: Arial">内充下发请联系：@kimkumma   @Wingtopstand</span>-->
          <!--                            </marquee>-->
          <!--                        </div>-->
        </div>
      </el-header>
      <el-main class="el-main" :style="elMainStyle">
        <el-tabs style="width: 100%" v-model="tabsValues" type="card" editable @edit="handleTabsEdit">
          <el-tab-pane
              :key="item.name"
              v-for="(item) in editableTabs"
              :label="item.title"
              :name="item.name"
          >
            <component :is="item.content"></component>
          </el-tab-pane>
          <!--              <el-tab-pane label="首页" name="1">-->
          <!--                <Home></Home>-->
          <!--              </el-tab-pane>-->
          <!--              <el-tab-pane label="代收列表" name="2">-->
          <!--                <PayLogList></PayLogList>-->
          <!--              </el-tab-pane>-->
        </el-tabs>
      </el-main>
    </el-container>
  </el-container>
</template>


<script>
import {getSessionCpInfo} from "@/api/cpinfo";
import Home from "@/views/Home";
import PayLogList from '@/views/pay/index'
import WithdrawLogList from '@/views/withdraw/index'
import MoneyLogList from '@/views/money/index'
import SettlementLogList from '@/views/settlement/index'
import {getSettings} from "@/api/settings";
import {
  Edit as ElEdit,
  Expand as ElExpand,
  Fold as ElFold,
  HomeFilled,
  Sell,
  SoldOut,
  List,
  Wallet
} from "@element-plus/icons-vue";

export default {
  // eslint-disable-next-line vue/multi-word-component-names
  name: "Index",
  components: {
    Home,
    PayLogList,
    WithdrawLogList,
    MoneyLogList,
    SettlementLogList,
    ElEdit,
    ElExpand,
    ElFold,
    HomeFilled,
    Sell,
    SoldOut,
    List,
    Wallet
  },
  data() {
    return {
      fullscreenLoading: true,
      editableTabsValue: 0,
      clientWidth: 0,
      clientHeight: 0,
      tabIndex: 2,
      isCollapse: false,
      iframe: 'home.html',
      menuList: [
        {
          id: 1,
          permissName: "记录查询",
          pType: "List",
          pValue: null,
          pLevel: 0,
          upId: 0,
          upName: null,
          sort: 1,
          createTime: "Jan 15, 2021 9:51:49 AM",
          children: [
            {
              id: 11,
              permissName: "交易记录",
              pType: '',
              pValue: "PayLogList",
              pLevel: 0,
              upId: 1,
              upName: null,
              sort: 1,
              createTime: "Jan 15, 2021 9:55:01 AM",
              children: null
            },
            {
              id: 12,
              permissName: "提现记录",
              pType: "",
              pValue: "WithdrawLogList",
              pLevel: 0,
              upId: 1,
              upName: null,
              sort: 2,
              createTime: "Jan 15, 2021 9:55:01 AM",
              children: null
            }
          ]
        },
        {
          id: 2,
          permissName: "财务管理",
          pType: "Wallet",
          pValue: null,
          pLevel: 0,
          upId: 0,
          upName: null,
          sort: 1,
          createTime: "Jan 15, 2021 9:51:49 AM",
          children: [
            {
              id: 11,
              permissName: "资金记录",
              pType: null,
              pValue: "MoneyLogList",
              pLevel: 0,
              upId: 1,
              upName: null,
              sort: 1,
              createTime: "Jan 15, 2021 9:55:01 AM",
              children: null
            },
            {
              id: 12,
              permissName: "余额结算",
              pType: null,
              pValue: "SettlementLogList",
              pLevel: 0,
              upId: 1,
              upName: null,
              sort: 1,
              createTime: "Jan 15, 2021 9:55:01 AM",
              children: null,
              show: false
            }
          ]
        }
      ],
      cpinfo: {
        username: ''
      },
      tabsValues: '1',
      editableTabs: [],
      elMainStyle: {},
      elAsideStyle: {},
      asideWidth: '14rem'
    }
  },
  watch: {
    clientWidth: function () {
      // eslint-disable-next-line no-empty
      if (this.clientWidth < 768) {
        this.isCollapse = true
        this.asideWidth = '4rem'
      } else {
        this.isCollapse = false
        this.asideWidth = '14rem'
      }
    },
    clientHeight: function () {
      this.changeFixed(this.clientHeight)
    },

  },
  mounted() {
    let that = this
    // 获取浏览器可视区域高度
    that.clientWidth = `${document.documentElement.clientWidth}`          //document.body.clientWidth;
    that.clientHeight = `${document.documentElement.clientHeight}`          //document.body.clientWidth;
    window.onresize = function temp() {
      that.clientWidth = `${document.documentElement.clientWidth}`;
      that.clientHeight = `${document.documentElement.clientHeight}`;
    }

  },
  created() {
    this.editableTabs = []
    this.addTabs({id: 1, permissName: '首页', pValue: 'home'})
    this.getCpInfo()
  },
  methods: {
    changeFixed(clientHeight) {
      this.elMainStyle = {
        height: clientHeight + 'px'
      }
      this.elAsideStyle = {
        height: clientHeight + 'px'
      }

    },
    changeMenu(){

    },
    ShowNavMenu() {
      this.isCollapse = !this.isCollapse
    },

    getIframeSrc(e) {
      this.iframe = e
    },
    checkoutLogin() {
      this.$router.push('/')
    },
    getCpInfo() {
      var that = this
      getSessionCpInfo().then(function (response) {
        if (response.data.code === 0) {
          var data = response.data.data
          that.cpinfo.username = data.userName
          if (that.cpinfo.username !== 'test1'){
            that.menuList[1].children.splice(1, 1)
          }
          sessionStorage.setItem("cpinfo", JSON.stringify(data))
        }
      })
    },
    handleTabsEdit(targetName, action) {
      if (action === 'add') {
        let newTabName = ++this.tabIndex + '';
        this.editableTabs.push({
          title: 'New Tab',
          name: newTabName,
          content: ''
        });
        this.tabsValues = newTabName;
      }
      if (action === 'remove') {
        let tabs = this.editableTabs;
        let activeName = this.tabsValues;
        if (activeName === targetName) {
          tabs.forEach((tab, index) => {
            if (tab.name === targetName) {
              let nextTab = tabs[index + 1] || tabs[index - 1];
              if (nextTab) {
                activeName = nextTab.name;
              }
            }
          });
        }
        this.tabsValues = activeName;
        this.editableTabs = tabs.filter(tab => tab.name !== targetName);
      }
    },
    addTabs(itemson) {
      const permissName = itemson.permissName
      const pValue = itemson.pValue

      if (pValue != null) {
        var newTab = (title, name, content, show) => {
          return {
            title: title,
            name: name,
            content: content,
            show: show
          }
        }

        for (const tab of this.editableTabs) {
          if (tab.name === pValue) {
            this.tabsValues = pValue
            return
          }
        }
        this.editableTabs.push(newTab(permissName, pValue, pValue, true))
      }

      this.$nextTick(() => {
        this.tabsValues = pValue
      })
    },
    getPlatformSettings() {
      var that = this
      getSettings().then((response) => {
        that.PlatformName = response.data.data.platformName
        var elementById = document.getElementById('title');
        elementById.html('111')
      })
    }

  }

}
</script>

<style>
/* 侧边栏头部信息头像区域 */
.top-info {
  padding: 10px;
  height: 130px;
}

.header__left {
  float: left;
}

</style>
