<template>
  <div id="app" v-cloak v-loading.fullscreen.lock="fullscreenLoading">
    <el-form :model="searchForm" ref="searchForm" label-width="90px">
      <el-row>
        <el-col :xl="3" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="系统订单号" prop="id">
            <el-input v-model="searchForm.id" placeholder=""></el-input>
          </el-form-item>
        </el-col>
        <el-col :xl="4" :lg="6" :md="6" :sm="8" :xs="1242" class="form-search">
          <el-form-item label="商户订单号" prop="orderId">
            <el-input v-model="searchForm.orderId" placeholder=""></el-input>
          </el-form-item>
        </el-col>
        <el-col :xl="4" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="订单状态" prop="status">
            <el-select v-model="searchForm.status" placeholder="请选择">
              <el-option label="请选择" value=""></el-option>
              <el-option label="成功" value="1"></el-option>
              <el-option label="待处理" value="0"></el-option>
              <el-option label="失败" value="-1"></el-option>
            </el-select>
          </el-form-item>
        </el-col>
        <el-col :xl="4" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="同步状态" prop="syncCnt">
            <el-select v-model="searchForm.syncCnt" placeholder="请选择">
              <el-option label="请选择" value=""></el-option>
              <el-option label="同步成功" value="1"></el-option>
              <el-option label="未回调" value="0"></el-option>
              <el-option label="失败重试" value="-1"></el-option>
            </el-select>
          </el-form-item>
        </el-col>
        <el-col v-if="cpinfo.country === 'MEX'" :xl="4" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="clabe" prop="clabe">
            <el-input v-model="searchForm.clabe" placeholder=""></el-input>
          </el-form-item>
        </el-col>
        <el-col v-if="cpinfo.country === 'MEX'" :xl="4" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="Clave De Rsstreo" prop="rastreo">
            <el-input v-model="searchForm.rastreo" placeholder=""></el-input>
          </el-form-item>
        </el-col>
        <el-col :xl="4" :lg="6" :md="6" :sm="8" :xs="24" class="form-search">
          <el-form-item label="金额" prop="amount">
            <el-input v-model="searchForm.amount" placeholder=""></el-input>
          </el-form-item>
        </el-col>
        <el-col :xl="4" :lg="8" :md="8" :sm="12" :xs="24" class="form-search">
          <el-form-item label="起始时间">
            <el-col :span="11">
              <el-date-picker
                  v-model="early"
                  type="datetimerange"
                  :clearable="true"
                  :default-time="defaultTime"
                  value-format="YYYY-MM-DD HH:mm:ss"
                  placeholder="选择起始日期"
              >
              </el-date-picker>
            </el-col>
          </el-form-item>
        </el-col>
      </el-row>
      <el-row >
        <el-button type="primary" @click="search">查询</el-button>
        <el-button @click="resetForm('searchForm')">重置</el-button>
        <el-button @click="exportPayLog()">导出</el-button>
      </el-row>

    </el-form>
    <div id="grid" style="width: 100%;margin-top: 20px">
      <el-table
          :data="tableData"
          style="width: 100%"
          size="small"
      >
        <el-table-column type="expand">
          <template #default="props">
            <el-form label-position="left" inline class="demo-table-expand">
              <el-form-item label="跳转地址">
                <span>{{ props.row.callbackUrl }}</span>
              </el-form-item>
              <el-form-item label="回调地址">
                <span>{{ props.row.notifyUrl }}</span>
              </el-form-item>
              <el-form-item label="备注">
                <span>{{ props.row.description }}</span>
              </el-form-item>
            </el-form>
          </template>
        </el-table-column>
        <el-table-column
            prop="id"
            label="订单号"
            align="center"
        >
        </el-table-column>
        <el-table-column
            prop="orderId"
            label="商户订单号"
            align="center">
        </el-table-column>
        <el-table-column
            prop="appId"
            label="商户Id"
            align="center">
        </el-table-column>
        <el-table-column
            prop="amount"
            label="金额"
            align="center">
        </el-table-column>
        <el-table-column
            prop="platformFee"
            label="商户手续费"
            align="center">
        </el-table-column>
        <el-table-column
            prop="type"
            label="充值类型"
            align="center">
        </el-table-column>
        <el-table-column
            label="订单状态"
            align="center">
          <template #default="scope">
            <span v-if="scope.row.status  === 1" class="settlement-status settlement-status-success">成功</span>
            <span v-if="scope.row.status  === 0" class="settlement-status settlement-status-initial">待处理</span>
          </template>
        </el-table-column>
        <el-table-column
            label="回调状态"
            align="center"
            width="90px"
        >
          <template #default="scope">
            <span v-if="scope.row.syncCnt  === 1" class="settlement-status settlement-status-success">同步成功</span>
            <span v-if="scope.row.syncCnt  === 0" class="settlement-status settlement-status-initial">待同步</span>
            <span v-if="scope.row.syncCnt  < 0" class="settlement-status settlement-status-reject">同步失败</span>
          </template>
        </el-table-column>
        <el-table-column
            prop="createTime"
            label="创建时间"
            align="center">
        </el-table-column>
        <el-table-column
            prop="payTime"
            label="支付时间"
            align="center">
        </el-table-column>
        <el-table-column
            prop="clabe"
            label="clabe"
            v-if="cpinfo.country === 'MEX'"
            align="center"
        ></el-table-column>
        <el-table-column
            prop="rastreo"
            label="Clave De Rastreo"
            v-if="cpinfo.country === 'MEX'"
            align="center"
        >
        </el-table-column>
        <el-table-column label="操作" width="300">
          <template #default="scope">
            <el-button v-if="(scope.row.status === '待处理' && scope.row.payTypeId === 101)" type="danger"
                       round
                       size="mini"
                       @click="openMatchUtrDrawer(scope)">人工补单
            </el-button>
          </template>
        </el-table-column>

      </el-table>
    </div>
    <div style="text-align: center;margin-top:5px;">
      <el-pagination
          background
          layout="total, prev, pager, next"
          :total="total" :current-page="searchForm.page" @current-change="pageChange">
      </el-pagination>
    </div>
    <el-drawer
        :visible="matchUtrDrawerVisible"
        :direction="direction"
        :before-close="handleClose"
        :close-on-click-modal="false"
        :show-close="false"
        custom-class="demo-drawer"
        style="overflow-y: auto"
        size="50%">
      <div class="" style="padding: 20px">
        <el-form>
          <el-form-item label="UTR" :label-width="formLabelWidth">
            <el-input v-model="matchUtrForm.rastreo" autocomplete="off"></el-input>
          </el-form-item>
        </el-form>
        <div class="demo-drawer__footer">
          <el-button :disable="matching" type="success" @click="matchUtr()">{{
              matching
                  ?
                  '匹配中...' : '确认'
            }}
          </el-button>
          <el-button @click="closeMatchUtrDrawer()">取 消</el-button>
        </div>
      </div>
    </el-drawer>
  </div>
</template>

<script>
import {matchUtr, queryPayLogPageList} from "@/api/payLog";
import {dateFormate, formatAmount, formatPayType} from "@/statics/custom";
import {allDictionaryByType} from "@/api/dictionary";

export default {
  // eslint-disable-next-line vue/multi-word-component-names
  name: "index",
  data() {
    return {
      fullscreenLoading: false,
      centerDialogVisible: false,
      innerVisible: false,
      sendNotifyDrawerVisable: false,
      direction: 'rtl',
      password: '',
      verifyCode: '',
      notifyId: '',
      early: [
      ],
      defaultTime: [
        new Date(2000, 1, 1, 0, 0, 0),
        new Date(2000, 2, 1, 23, 59, 59),
      ],
      countryOptions: [],
      payTypeOptions: [],
      searchFormOri: {},
      searchForm: {
        id: '',
        orderId: '',
        type: '',
        status: '',
        syncCnt: '',
        startCreateTime: '',
        endCreateTime: '',
        startPayTime: '',
        endPayTime: '',
        clabe: '',
        rastreo: '',
        pix_key: '',
        document_id: '',
        amount: '',
        page: 1,
        limit: 10,
        rowIndex: 0
      },
      dialog: {
        isInsert: true,
        visible: false,
        formLabelWidth: '150px',
        form: {},
        settings: {
          visible: false,
          activeName: 'first',
          userName: '',
          appId: 0,
          payFix: 0,
          payRate: 0,
          withdrawFix: 0,
          withdrawRate: 0,
          balanceForm: {
            password: '',
            Verifycode: '',
            remain: 0,
            Notes: ''
          }
        },
        rules: {
          UserName: [
            {required: true, message: '请输入账号名称', trigger: 'blur'},
            {min: 3, max: 50, message: '长度在 3 到 50 个字符', trigger: 'blur'}
          ]
        },
      },
      tableData: [],
      total: 0,
      dateStart: '', // 起运日期
      dateEnd: '', // 送达日期
      pickerOptionsStart: {},
      pickerOptionsEnd: {
        disabledDate(time) {
          let startTime = null
          if (this.dateStart) {
            // 让用户可以选择开始结束同一天
            startTime = new Date(this.dateStart).valueOf() - 8.64e7 + 1;
          } else {
            startTime = Date.now() - 8.64e7;
          }
          return time && time.valueOf() < startTime
        }
      },
      notifyBtnSwitch: 'disabled',
      sendNotifyMsgForm: {
        id: '',
        url: '',
        notifyData: '',
        notifyResp: '',
        notifyAnalyze: ''
      },
      formLabelWidth: 120,
      sending: false,
      cpinfo: {
        country: ''
      },
      matching: false,
      matchUtrDrawerVisible: false,
      matchUtrForm: {
        id: '',
        rastreo: ''
      },

    }
  },
  created() {
    this.queryAllPayLog()
    this.initCpinfo()
  },
  methods: {
    queryAllPayLog() {
      var that = this
      this.fullscreenLoading = true
      console.log(this.early)
      this.searchForm.startCreateTime = this.early === [] ? [] : this.early[0]
      this.searchForm.endCreateTime = this.early === [] ? [] : this.early[1]
      queryPayLogPageList(this.searchForm).then(function (response) {
        if (response.data.code === 0) {

          var list = response.data.data.list
          var statictics = response.data.data.statictics

          var tableData = []
          for (var paylog of list) {

            paylog.type = formatPayType(paylog)
            paylog.amount = formatAmount(paylog.amount)
            paylog.platformFee = formatAmount(paylog.platformFee)

            var validStatus = paylog.validStatus
            validStatus = validStatus === 1 ? '已结算' : '未结算'
            paylog.validStatus = validStatus

            paylog.createTime = dateFormate(paylog.createTime)
            paylog.payTime = dateFormate(paylog.payTime)

            tableData.push(paylog)
          }
          that.tableData = tableData
          that.total = statictics.allPayNum
          that.fullscreenLoading = false
        }
      })
    },
    queryCountryPageList() {
      let that = this
      allDictionaryByType({type: 'country'}).then(function (res) {
        if (res.data.code === 0) {
          that.countryOptions = []
          res.data.data.forEach((item) => {
            that.countryOptions.push(
                {
                  "label": item.name,
                  "value": item.value
                }
            )
          })
        }
      })
    },
    search() {
      console.log('early:'+this.early)
      this.searchForm.page = 1
      this.queryAllPayLog()
    },
    resetForm(formName) {
      this.$refs[formName].resetFields()
      this.early = []
    },
    pageChange(cur) {
      this.searchForm.page = cur
      this.queryAllPayLog()
    },
    closeDialog() {
      this.dialog.visible = false
      this.dialog.isInsert = true
      this.commonCloseDialog(this.dialog.form, 'ruleForm')
    },
    openSendNotifyMsgDrawer(data) {
      this.sendNotifyMsgForm.id = ''
      this.sendNotifyMsgForm.id = data.id
      this.sendNotifyMsgForm.url = ''
      this.sendNotifyMsgForm.url = data.notifyUrl
      this.sendNotifyMsgForm.notifyData = ''
      this.sendNotifyMsgForm.notifyResp = ''
      this.sendNotifyMsgForm.notifyAnalyze = ''
      this.sendNotifyDrawerVisable = true
    },
    handleClose(done) {
      done();
    },
    cancelNotifyMsgDrawer() {
      this.sendNotifyDrawerVisable = false
      this.sendNotifyMsgForm.notifyData = ''
      this.sendNotifyMsgForm.notifyResp = ''
      this.sendNotifyMsgForm.notifyAnalyze = ''
    },
    initCpinfo() {
      var data = JSON.parse(sessionStorage.getItem("cpinfo"))
      this.cpinfo.country = data.country
    },
    exportPayLog() {
      //编码防止中文字符乱码
      window.location.href = encodeURI("/pay/paylog/exportPayLog?id=" + this.searchForm.id + "&orderId=" + this.searchForm.orderId + "&type=" + this.searchForm.type + "&status=" + this.searchForm.status + "&syncCnt=" + this.searchForm.syncCnt + "&startCreateTime=" + (this.searchForm.startCreateTime === undefined ? "" : this.searchForm.startCreateTime) + "&endCreateTime=" + (this.searchForm.endCreateTime === undefined ? "" : this.searchForm.endCreateTime) + "&startPayTime=" + (this.searchForm.startPayTime === undefined ? "" : this.searchForm.startPayTime) + "&endPayTime=" + (this.searchForm.endPayTime === undefined ? "" : this.searchForm.endPayTime) + "&clabe=" + this.searchForm.clabe + "&pix_key=" + this.searchForm.pix_key + "&document_id=" + this.searchForm.document_id + "&amount=" + this.searchForm.amount)
    },
    openMatchUtrDrawer(scope) {
      const currency = scope.row.currency
      if (currency === 'INR') {
        this.matchUtrForm.id = scope.row.id

        this.matchUtrDrawerVisible = true
      }
    },
    closeMatchUtrDrawer() {
      this.matchUtrForm.id = ''
      this.matchUtrForm.utr = ''
      this.matchUtrDrawerVisible = false
    },
    matchUtr() {
      const that = this
      matchUtr(that.matchUtrForm).then((response) => {
        const data = response.data
        const code = data.code
        if (code === 0) {
          that.closeMatchUtrDrawer()
          that.queryAllPayLog()
        }
        that.$message(data.msg)
      })
    }
  }
}
</script>

<style scoped>

</style>
