/* 1.引入文件 */
import axios from 'axios'

/* 2.全局默认配置 */
let baseURL
// 判断开发环境（一般用于本地代理）
if (process.env.NODE_ENV === 'development') { // 开发环境
    baseURL = '/api'    // 你设置的本地代理请求（跨域代理），下文会详细介绍怎么进行跨域代理
} else {                                      // 编译环境
    if (process.env.type === 'test') {        // 测试环境

        baseURL = 'http://localhost:8686/pay'
    } else {
// 正式环境
        baseURL = '/pay'
    }
}
// 配置axios的属性
axios.defaults.timeout = 60000;    // 请求超时时间1分钟
axios.defaults.baseURL = baseURL; // 你的接口地址
//axios.defaults.responseType="json";
axios.defaults.withCredentials = false;  //是否允许带cookie这些

axios.interceptors.request.use(
    config => {
        if (localStorage.getItem('CpInfo_Authorization')) {
            config.headers.Authorization = localStorage.getItem('CpInfo_Authorization');
        }

        return config;
    },
    error => {
        return Promise.reject(error);
    });

axios.interceptors.response.use(
    response => {
        console.log(response)
        if (response.data.code === 444) {
            window.location.href = '/'
        }
        return response
    }
)
export default axios


